import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{i,n as a,r as o,t as s}from"./chunks/windows-wizard-screenshot.QBlzzreT.js";const c=JSON.parse(`{"title":"Установлення Java на Windows","description":"Покрокова інструкція щодо встановлення Java на Windows.","frontmatter":{"title":"Установлення Java на Windows","description":"Покрокова інструкція щодо встановлення Java на Windows.","authors":["IMB11","skycatminepokie"],"next":false,"files":[]},"headers":[],"relativePath":"uk_ua/players/installing-java/windows.md","filePath":"translated/uk_ua/players/installing-java/windows.md","lastUpdated":1774518827000}`);var l={name:`uk_ua/players/installing-java/windows.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Установлення Java на Windows <a class="header-anchor" href="#h1" aria-label="Permalink to “Установлення Java на Windows”">​</a></h1><p>Інструкція з того, як установити Java 21 у Windows.</p><p>Запускач Minecraft постачається з власним установленням Java, тому цей розділ актуальний, лише якщо ви хочете використовувати встановлювач на основі Fabric <code>.jar</code> або якщо ви хочете використовувати сервер Minecraft <code>.jar</code>.</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. Перевірте, чи Java уже встановлено <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. Перевірте, чи Java уже встановлено”">​</a></h2><p>Щоб перевірити, чи Java вже встановлено, потрібно спочатку відкрити командний рядок.</p><p>Ви можете зробити це, натиснувши <kbd>Windows</kbd>+<kbd>R</kbd> і ввівши <code>cmd.exe</code> у поле, що з’явиться.</p><p><img src="/assets/players/installing-java/windows-run-dialog.png" alt="Діалогове вікно запуску Windows із «cmd.exe» на панелі запуску" loading="lazy"></p><p>Відкривши командний рядок, введіть <code>java -version</code> і натисніть <kbd>Enter</kbd>.</p><p>Якщо команда виконана успішно, ви побачите щось подібне. Якщо команда не вдалася, перейдіть до наступного кроку.</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Командний рядок із введеним «java -version»" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Щоб використовувати Minecraft 1.21.11, вам потрібно встановити принаймні Java 21.</p><p>Якщо ця команда показує будь-яку версію, нижчу за 21, вам потрібно буде оновити наявну інсталяцію Java; продовжуйте читати цю сторінку.</p></div><h2 id="2-download-the-java-installer" tabindex="-1">2. Завантажити Завантажувач Java 21 <a class="header-anchor" href="#2-download-the-java-installer" aria-label="Permalink to “2. Завантажити Завантажувач Java 21”">​</a></h2><p>Щоб установити Java 21, вам потрібно буде завантажити встановлювач з <a href="https://adoptium.net/temurin/releases?version=21&amp;os=windows&amp;arch=any&amp;mode=filter" target="_blank" rel="noreferrer">Adoptium</a>.</p><p>Ви захочете завантажити версію <code>Windows Installer (.msi)</code>:</p><p><img src="/assets/players/installing-java/windows-download-java.png" alt="Сторінка завантаження Adoptium із виділеним установлювачем Windows (.msi)" loading="lazy"></p><p>Вам слід вибрати «x86», якщо у вас 32-розрядна операційна система, або «x64», якщо у вас 64-розрядна операційна система.</p><p>Більшість сучасних комп’ютерів матиме 64-розрядну операційну систему. Якщо ви не впевнені, спробуйте скористатися 64-розрядним завантаженням.</p><h2 id="3-run-the-installer" tabindex="-1">3. Запустіть установлювач! <a class="header-anchor" href="#3-run-the-installer" aria-label="Permalink to “3. Запустіть установлювач!”">​</a></h2><p>Виконайте кроки встановлювача, щоб встановити Java 21. Коли ви перейдете на цю сторінку, ви повинні встановити такі функції на «Уся функція буде встановлена ​​на локальному носію»:</p><ul><li><code>Установити змінну середовища JAVA_HOME</code> — її буде додано до вашого PATH.</li><li><code>JavaSoft (Oracle) registry keys</code></li></ul><p><img src="/assets/players/installing-java/windows-wizard-screenshot.png" alt="Установлювач Java 21 із виділеними параметрами «Установити змінну JAVA_HOME» і «ключами реєстру JavaSoft (Oracle)»" loading="lazy"></p><p>Зробивши це, ви можете натиснути <code>Next</code> і продовжити встановлення.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Windows не завжди повідомлятиме іншим програмам, що Java встановлено, доки ви не перезавантажите комп’ютер.</p><p><strong>Перш ніж продовжити, обов’язково перезавантажте комп’ютер!</strong></p></div><h2 id="4-verify-that-java-is-installed" tabindex="-1">4. Перевірте, чи встановлено Java 21 <a class="header-anchor" href="#4-verify-that-java-is-installed" aria-label="Permalink to “4. Перевірте, чи встановлено Java 21”">​</a></h2><p>Після завершення встановлення ви можете переконатися, що Java 21 встановлено, знову відкривши командний рядок і ввівши <code>java -version</code>.</p><p>Якщо команда виконана успішно, ви побачите щось подібне до показаного раніше, де показана версія Java:</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Командний рядок із введеним «java -version»" loading="lazy"></p><p>Якщо у вас виникнуть проблеми, не соромтеся звертатися по допомогу до <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> на каналі <code>#player-support</code>.</p>`,28)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};